    /**
     * Execute a user-defined action by running JavaScript code configured in preferences
     * @param actionNumber The user action number (1-9)
     * @return true if the action was executed, false if no JavaScript is configured
     */
    private fun executeUserAction(actionNumber: Int): Boolean {
        val prefKey = "userAction$actionNumber"
        val jsCode = sharedPrefs().getString(prefKey, "")?.trim()

        if (jsCode.isNullOrEmpty()) {
            Timber.d("User Action $actionNumber: No JavaScript configured")
            return false
        }

        Timber.i("User Action $actionNumber: Executing JavaScript: %s", jsCode)
        loadUrlInViewer("javascript: $jsCode")
