package com.ichi2.anki.preferences

import android.content.Context
import android.content.Intent
import android.net.Uri
import android.util.AttributeSet
import androidx.preference.PreferenceCategory
import androidx.preference.PreferenceViewHolder

/**
 * A PreferenceCategory that supports a help link
 * The help link is specified via the app:helpLink attribute
 */
class ExtendedPreferenceCategory @JvmOverloads constructor(
    context: Context,
    attrs: AttributeSet? = null,
    defStyleAttr: Int = androidx.preference.R.attr.preferenceCategoryStyle,
    defStyleRes: Int = 0
) : PreferenceCategory(context, attrs, defStyleAttr, defStyleRes) {

    private var helpLink: String? = null

    init {
        if (attrs != null) {
            val typedArray = context.obtainStyledAttributes(attrs, intArrayOf(
                context.resources.getIdentifier("helpLink", "attr", context.packageName)
            ))
            helpLink = typedArray.getString(0)
            typedArray.recycle()
        }
    }

    override fun onBindViewHolder(holder: PreferenceViewHolder) {
        super.onBindViewHolder(holder)

        // If a help link is specified, make the preference clickable
        if (!helpLink.isNullOrEmpty()) {
            holder.itemView.setOnClickListener {
                openHelpLink()
            }
        }
    }

    private fun openHelpLink() {
        helpLink?.let { link ->
            val resolvedLink = if (link.startsWith("@string/")) {
                val resourceName = link.substring(8) // Remove "@string/"
                val resourceId = context.resources.getIdentifier(resourceName, "string", context.packageName)
                if (resourceId != 0) {
                    context.getString(resourceId)
                } else {
                    link
                }
            } else {
                link
            }

            val intent = Intent(Intent.ACTION_VIEW, Uri.parse(resolvedLink))
            context.startActivity(intent)
        }
    }
}
